## Code Example
```javascript
// Online Infomax-like ICA implementation
function onlineICA(whitenedData, learningRate) {
  // Initialize separation matrix
  let W = initializeMatrix();

  return function update(newSample) {
    // Natural gradient update
    const y = W * newSample;
    const g = tanh(y);
    const delta = learningRate * (g * newSample - (1 - g * g) * W);

    // Update separation matrix
    W += delta;
    return y;
  };
}
```

