## Code Example
```javascript
// Pseudocode: Online whitening with forgetting factor
class OnlineWhitener {
  constructor(dim, forgettingFactor = 0.99) {
    this.dim = dim;
    this.forgettingFactor = forgettingFactor;
    this.covariance = zeros(dim, dim);
    this.eigenvectors = eye(dim);
    this.eigenvalues = ones(dim);
  }

  update(x) {
    this.covariance = this.forgettingFactor * this.covariance + (1 - this.forgettingFactor) * (x * x.T);
    const { V, D } = eig(this.covariance);
    this.eigenvectors = V;
    this.eigenvalues = D;
    const invSqrtD = diag(D.map(d => 1 / Math.sqrt(d + 1e-8)));
    return invSqrtD * V.T * x;
  }
}
```

