## Code Example
```javascript
// Online ICA update with natural gradient
function onlineICA(X, W, lambda = 0.98, eps = 1e-8) {
  const [nMic, nFrame, nBin] = X.shape;
  const Xw = new Float32Array(nMic, nFrame, nBin);
  const W_new = new Float32Array(12, 3, nBin);

  for (let bin = 0; bin < nBin; bin++) {
    const X_bin = X.slice(:,:,bin);   // [nMic, nFrame]
    const W_bin = W[:,:,bin];          // [12, 3]

    // Whitening via exponential moving average
    const R = (1 - lambda) * X_bin @ X_bin.T + lambda * R;
    const V = inv(sqrtm(R + eps * eye(nMic)));
    const Xw_bin = V @ X_bin;

    // Natural gradient update: W ← W + μ(I - E[y y^T])W
    const Y = W_bin.T @ Xw_bin;               // [3, nFrame]
    const G = (Y @ Y.T) / nFrame;              // [3, 3]
    const delta = (eye(3) - G) @ W_bin;
    W_new[:,:,bin] = W_bin + 0.1 * delta;      // μ = 0.1
    Xw(:,:,bin) = Xw_bin;
  }
  return { W: W_new, Xw };
}
```

