function onlineWhiten(x, forgetFactor, state) {
  const alpha = forgetFactor;
  state.mean = alpha * state.mean + (1 - alpha) * x;
  state.cov = alpha * state.cov + (1 - alpha) * (x - state.mean).outer(x - state.mean);
  const whitened = (x - state.mean) * inv(sqrt(eigenvalues(state.cov)));
  return whitened;
}
