## Code Example
```python
import numpy as np

class OnlineConvolutiveICA:
    def __init__(self, n_mics=3, n_sources=3, fft_size=1024, hop_size=512, forgetting_factor=0.99):
        self.n_mics = n_mics
        self.n_sources = n_sources
        self.fft_size = fft_size
        self.hop_size = hop_size
        self.alpha = forgetting_factor
        self.W = {}

    def compute_stft(self, x):
        return np.stack([np.fft.rfft(x[i], self.fft_size) for i in range(self.n_mics)])

    def whiten(self, X):
        cov = np.cov(X)
        eigvals, eigvecs = np.linalg.eigh(cov)
        return eigvecs @ np.diag(1.0 / np.sqrt(eigvals + 1e-8)) @ eigvecs.T @ X

    def online_update(self, X_bin, method='convolutive'):
        if method == 'instantaneous':
            self._update_instantaneous(X_bin)
        else:
            self._update_convolutive(X_bin)

    def _update_instantaneous(self, X):
        for key in self.W:
            self.W[key] = self._natural_gradient(self.W[key], X)

    def _update_convolutive(self, X):
        pass

    def _natural_gradient(self, W, X):
        lr = 0.01
        W_new = W + lr * (np.eye(W.shape[0]) - W @ X @ X.T.conj() / (X.T.conj() @ X + 1e-8)) @ W
        return self.alpha * W + (1 - self.alpha) * W_new

    def detect_nonstationarity(self, X, window=10):
        variance = np.var(np.abs(X), axis=-1)
        return np.std(variance, axis=-1) > 0.5

    def resolve_permutation(self, S):
        n_bins = S.shape[1]
        for b in range(1, n_bins):
            coherence = np.abs(np.corrcoef(S[0, b-1], S[0, b])[:2, :2])
            perm = np.argmax(coherence, axis=1)
            S[:, b] = S[perm, b]
        return S
```

