const FORGETTING_FACTOR = 0.97;
const STFT_SIZE = 1024;
const HOP_SIZE = 512;

let whiteningMatrix = null;
let demixer = null;

function updateICAFrame(fftBuffer, imuData) {
  // Step 1: Compute STFT and form observation vector
  const obs = formObservationVector(fftBuffer); // shape: [6, nBins]

  // Step 2: Recursive whitening with forgetting factor
  if (whiteningMatrix === null) {
    whiteningMatrix = initializeWhitening(obs);
  } else {
    whiteningMatrix = updateWhitening(whiteningMatrix, obs, FORGETTING_FACTOR);
  }
  const whitened = whiteningMatrix.matmul(obs);

  // Step 3: Per-bin ICA update using natural gradient
  const nBins = whitened.shape[1];
  for (let bin = 0; bin < nBins; bin++) {
    const x = whitened.col(bin); // [6, 1]
    demixer[bin] = updateDemixer(demixer[bin], x, imuData.rotationRate);
  }

  // Step 4: Cross-bin permutation correction using IMU
  const phaseCorrection = computeRotationPhase(imuData.rotationRate);
  applyPermutationCorrection(demixer, phaseCorrection);

  // Step 5: Compute separated sources
  const separated = demixer.map(d => d.matmul(whitened));
  return separated;
}

function updateDemixer(W, x, rotationRate) {
  // Natural gradient update: W = W + μ(I - g(y)y^T)W
  const y = W.matmul(x);
  const g = Math.tanh(y); // sigmoid nonlinearity for super-Gaussian sources
  const gradient = (I - g.matmul(y.T)).matmul(W);
  const learningRate = 0.01 * (1 + Math.abs(rotationRate) / 90);
  return W + learningRate * gradient;
}
