```javascript
class OnlineConvolutiveICA {
  constructor(numMics = 14, numSources = 3, windowSize = 1024, hopSize = 512) {
    this.numMics = numMics;
    this.numSources = numSources;
    this.windowSize = windowSize;
    this.hopSize = hopSize;
    this.forgettingFactor = 0.995;
    this.W = new Array(numSources).fill(null).map(() => 
      new Array(numMics).fill(null).map(() => 
        new ComplexArray(numMics)
      )
    );
    this.sourceCount = 0;
    this.permutationCache = new Map();
  }

  processFrame(x) {
    const X = stft(x, this.windowSize, this.hopSize);
    const numBins = X.length;
    const separated = new Array(numBins);

    for (let k = 0; k < numBins; k++) {
      const Xk = X[k];
      const Wk = this.initializeDemixerIfNeeded(k);

      const Yk = this.perBinICA(Xk, Wk);
      separated[k] = Yk;
      this.updateDemixer(Xk, Yk, k);
    }

    this.resolvePermutation(separated);
    this.detectSourceCount(X);

    return istft(separated, this.windowSize, this.hopSize);
  }

  perBinICA(Xk, Wk) {
    const whitened = this.whiten(Xk);
    const Y = matMul(Wk, whitened);
    return this.applyNonlinearity(Y);
  }

  resolvePermutation(separated) {
    for (let k = 1; k < separated.length; k++) {
      const score = this.computeEnvelopeCorrelation(
        separated[k-1], 
        separated[k]
      );
      if (score > 0.7) {
        this.alignPermutation(separated[k-1], separated[k]);
      }
    }
  }

  detectSourceCount(X) {
    const cov = this.computeSpatialCovariance(X);
    const eigenvalues = this.eigenDecompose(cov);
    const gaps = this.computeEigenvalueGaps(eigenvalues);
    this.sourceCount = this.estimateSourceCount(gaps);
  }

  computeMetrics(separated, groundTruth) {
    return {
      SDR: this.signalToDistortionRatio(separated, groundTruth),
      SIR: this.signalToInterferenceRatio(separated, groundTruth)
    };
  }
}
```

